def word_break(s, word_dict):
    def word_break_helper(s, word_dict, memo):
        if s in memo:
            return memo[s]

        if not s:
            return [""]

        result = []
        for word in word_dict:
            if s.startswith(word):
                suffix = s[len(word):]
                suffix_sentences = word_break_helper(suffix, word_dict, memo)
                for sentence in suffix_sentences:
                    if sentence:
                        result.append(word + " " + sentence)
                    else:
                        result.append(word)

        memo[s] = result
        return result

    return word_break_helper(s, set(word_dict), {})
